下面是手写一个完整、生产可用的 **JavaScript debounce** 函数：

```javascript
/**
 * 创建一个 debounce（防抖）函数
 * @param {Function} fn         需要防抖处理的函数
 * @param {number}   delay      延迟时间（毫秒）
 * @param {Object}   options    可选配置
 * @param {boolean}  options.leading  是否在延迟开始前立即执行（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 经过防抖包装的函数，自带 .cancel() 方法
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;

  let timer = null;
  let lastArgs = null;
  let isLeadingCalled = false;

  const invoke = (context, args) => {
    fn.apply(context, args);
    timer = null;
    lastArgs = null;
    isLeadingCalled = false;
  };

  const debounced = function (...args) {
    lastArgs = args;
    const context = this;

    // leading 模式：如果 timer 空闲，立即执行一次
    if (leading && !timer && !isLeadingCalled) {
      isLeadingCalled = true;
      invoke(context, args);
      // 但 leading 调用后仍需设置 timer 来阻止 trailing 重复执行
    }

    // 清除上次的 timer
    if (timer) {
      clearTimeout(timer);
    }

    // 如果 trailing == false 且 leading 已经执行过，就不设 timer 了
    if (!trailing && isLeadingCalled) {
      return;
    }

    timer = setTimeout(() => {
      if (trailing) {
        invoke(context, lastArgs);
      } else {
        timer = null;
        isLeadingCalled = false;
      }
    }, delay);
  };

  /** 取消未执行的防抖调用 */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
    }
    timer = null;
    lastArgs = null;
    isLeadingCalled = false;
  };

  /** 立即执行并清空 */
  debounced.flush = function () {
    if (timer) {
      clearTimeout(timer);
      invoke(this, lastArgs);
    }
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 1. 基本用法 —— 搜索输入框防抖
const searchInput = document.getElementById('search');
const handleSearch = debounce((e) => {
  console.log('发起搜索:', e.target.value);
}, 300);

searchInput.addEventListener('input', handleSearch);

// 2. leading（先执行一次，然后再防抖）
const clickBtn = debounce(() => {
  console.log('按钮点击（立即执行一次，后续防抖）');
}, 500, { leading: true, trailing: false });

// 3. 取消 & 立即执行
const save = debounce(() => console.log('保存中...'), 2000);
save();
save.cancel();          // 取消未执行的保存

const log = debounce(() => console.log('flush'), 1000);
log();
log.flush();            // 立即执行，不等 1 秒
```

---

## 核心原理

| 概念 | 说明 |
|------|------|
| **timer** | 通过 `setTimeout` 延迟执行，每次调用时先 `clearTimeout` 再重设定时器 |
| **leading** | 第一次调用立即执行，后续快速调用被忽略，直到停顿超过 delay 才重置 |
| **trailing** | 默认 true，停顿结束后执行最后一次调用 |
| **cancel()** | 清除定时器，适合组件卸载时清理，防止内存泄漏 |
| **flush()** | 立即触发 pending 的调用，适合表单提交前"强制落库" |

---

## Lodash 风格的精简版（最常用）

如果你只需要最常见的 trailing 防抖（输入框场景）：

```javascript
function debounce(fn, delay) {
  let timer = null;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

> **一句话总结**：防抖把**连续触发**合并为**一次执行**，关键就是「每次调用都重置定时器」。

